import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/modules/blelink.png",m=JSON.parse('{"title":"BLE Hub Link","description":"","frontmatter":{},"headers":[],"relativePath":"modules/blelink.md","filePath":"modules/blelink.md"}'),s={name:"modules/blelink.md"};function l(i,t,d,u,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="ble-hub-link" tabindex="-1">BLE Hub Link <a class="header-anchor" href="#ble-hub-link" aria-label="Permalink to &quot;BLE Hub Link&quot;">​</a></h1><p><strong>Category:</strong> Hardware I/O</p><p>Passive BLE5 receiver that listens for broadcasts from the studio hub (Icon iControls via USB host). Outputs four control signals for the assigned channel slot. The slot number is set per-device using the BLELINK serial command, not in the patch. BLELINK and BLE MIDI are mutually exclusive on the same device.</p><img src="'+n+'" alt="blelink module"><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>fader</strong></td><td>Fader position 0-1 (pitch bend 0-16383 normalised). The channel strip fader on the hub.</td></tr><tr><td><strong>encoder</strong></td><td>V-Pot accumulated value 0-1 (0-255 normalised). Turns without limit; connect to a parameter via a CVMath offset.</td></tr><tr><td><strong>mute</strong></td><td>Mute button gate: 1 when muted, 0 when unmuted.</td></tr><tr><td><strong>solo</strong></td><td>Solo button gate: 1 when soloed, 0 when not.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Set the slot on each SCM individually: type BLELINK ON 0 in the console for channel 1 (slot 0), BLELINK ON 1 for channel 2, etc. The slot is saved to NVS and persists across reboots. Use BLELINK STATUS to verify packets are arriving. Connect fader to VCA gain for volume control, or to filter cutoff for a timbral fader. Mute/solo outputs are held (latched) — connect to a GateGen or ADSR gate input.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',9)])])}const b=e(s,[["render",l]]);export{m as __pageData,b as default};
